"use client";
import { useEffect, useState } from "react";
import { getLogo } from "@/lib/utils";
import { useSession } from "next-auth/react";
import {
    Wallet,
    ArrowUpRight,
    ArrowDownLeft,
    Eye,
    EyeOff,
    Landmark,
    TrendingUp
} from "lucide-react";
// Import Recharts
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

export default function DashboardPage() {
    const { data: session } = useSession();
    const [summary, setSummary] = useState<{ balance: number; walletDetails: any[] } | null>(null);
    const [transactions, setTransactions] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [showBalance, setShowBalance] = useState(false);

    const nickname = session?.user?.name?.split(" ")[0] || "User";

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [resSummary, resTx] = await Promise.all([
                    fetch("/api/dashboard/summary"),
                    fetch("/api/transactions/recent")
                ]);
                if (resSummary.ok) setSummary(await resSummary.json());
                if (resTx.ok) setTransactions(await resTx.json());
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const incomeTxs = transactions.filter(tx => tx.type === "INCOME").slice(0, 3);
    const expenseTxs = transactions.filter(tx => tx.type === "EXPENSE").slice(0, 3);

    const totalIncome = transactions.filter(tx => tx.type === "INCOME").reduce((acc, curr) => acc + curr.amount, 0);
    const totalExpense = transactions.filter(tx => tx.type === "EXPENSE").reduce((acc, curr) => acc + curr.amount, 0);
    
    const chartData = [
        { name: 'Pemasukan', value: totalIncome || 1 },
        { name: 'Pengeluaran', value: totalExpense || 1 },
    ];
    const COLORS = ['#10b981', '#3b82f6'];

    const formatCurrency = (amount: number) => {
        return showBalance ? `Rp ${amount.toLocaleString("id-ID")}` : "Rp ••••••••";
    };

    if (loading) return (
        <div className="flex items-center justify-center min-h-screen">
            <p className="p-8 text-center animate-pulse text-slate-500 font-mono italic">
                Memetakan dana {nickname}...
            </p>
        </div>
    );

    return (
        <div className="p-4 md:p-8 space-y-8 transition-colors duration-300">
            <div className="max-w-7xl mx-auto space-y-8">
                
                {/* 1. TOP SECTION: BALANCE & PIE CHART */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Saldo Utama */}
                    <div className="lg:col-span-2 bg-blue-600 p-8 rounded-[2.5rem] shadow-lg shadow-blue-200 dark:shadow-none text-white relative overflow-hidden group">
                        <div className="relative z-10">
                            <div className="flex justify-between items-center max-w-[220px]">
                                <p className="text-blue-100 text-sm font-bold uppercase tracking-widest">Total Balance</p>
                                <button onClick={() => setShowBalance(!showBalance)} className="bg-white/10 hover:bg-white/20 p-2 rounded-xl transition-all">
                                    {showBalance ? <EyeOff size={18} /> : <Eye size={18} />}
                                </button>
                            </div>
                            <h2 className="text-5xl md:text-6xl font-black mt-4 tracking-tighter">
                                {formatCurrency(summary?.balance || 0)}
                            </h2>
                        </div>
                        <Wallet className="absolute right-[-20px] bottom-[-20px] opacity-10 group-hover:scale-110 transition-transform duration-700" size={200} />
                    </div>

                    {/* PIE CHART BOX */}
                    <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-800 flex flex-col items-center justify-center transition-colors">
                        <h3 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] mb-4">Cashflow Ratio</h3>
                        <div className="w-full h-40">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie data={chartData} innerRadius={50} outerRadius={70} paddingAngle={8} dataKey="value" stroke="none">
                                        {chartData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <Tooltip 
                                        contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        </div>
                        <div className="flex gap-4 text-[10px] font-black mt-4">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-emerald-500"/> IN</div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"/> OUT</div>
                        </div>
                    </div>
                </div>

                {/* 2. MIDDLE SECTION: WALLETS & DUAL HISTORY */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    
                    {/* Daftar Dompet */}
                    <div className="lg:col-span-1 space-y-4">
                        <h3 className="font-black text-slate-800 dark:text-slate-200 text-sm uppercase tracking-widest px-2">Daftar Akun</h3>
                        <div className="grid grid-cols-1 gap-3">
                            {summary?.walletDetails?.map((wallet, idx) => (
                                <div key={idx} className="bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-100 dark:border-slate-800 flex justify-between items-center shadow-sm hover:border-blue-500/50 transition-all">
                                    <div className="flex items-center gap-4">
                                        <div className="w-12 h-12 bg-slate-50 dark:bg-slate-800 rounded-2xl flex items-center justify-center p-2">
                                            {getLogo(wallet.name) ? <img src={getLogo(wallet.name)} className="w-full h-full object-contain" /> : <Landmark size={20} className="text-slate-400"/>}
                                        </div>
                                        <div>
                                            <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{wallet.name}</p>
                                            <p className="text-[10px] text-slate-400 font-bold uppercase">{wallet.type}</p>
                                        </div>
                                    </div>
                                    <p className="text-sm font-black text-slate-900 dark:text-white">{formatCurrency(wallet.balance)}</p>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* RIWAYAT INCOME */}
                    <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
                        <h3 className="text-emerald-500 font-black text-xs uppercase tracking-widest mb-8 flex items-center gap-3">
                            <div className="p-2 bg-emerald-500/10 rounded-lg"><ArrowUpRight size={16} /></div> 
                            Income
                        </h3>
                        <div className="space-y-6">
                            {incomeTxs.map((tx, i) => (
                                <HistoryItem key={i} tx={tx} color="text-emerald-500" bg="bg-emerald-500/10" />
                            ))}
                        </div>
                    </div>

                    {/* RIWAYAT EXPENSE */}
                    <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
                        <h3 className="text-blue-500 font-black text-xs uppercase tracking-widest mb-8 flex items-center gap-3">
                            <div className="p-2 bg-blue-500/10 rounded-lg"><ArrowDownLeft size={16} /></div> 
                            Expense
                        </h3>
                        <div className="space-y-6">
                            {expenseTxs.map((tx, i) => (
                                <HistoryItem key={i} tx={tx} color="text-blue-500" bg="bg-blue-500/10" />
                            ))}
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
}

function HistoryItem({ tx, color, bg }: any) {
    return (
        <div className="flex justify-between items-center group">
            <div className="flex gap-4 items-center">
                <div className={`w-10 h-10 rounded-xl ${bg} ${color} flex items-center justify-center group-hover:scale-110 transition-transform`}>
                    <TrendingUp size={16}/>
                </div>
                <div>
                    <p className="text-sm font-bold text-slate-700 dark:text-slate-300 truncate max-w-[120px]">
                        {tx.description || tx.category?.name}
                    </p>
                    <p className="text-[10px] text-slate-400 font-medium">
                        {new Date(tx.createdAt).toLocaleDateString("id-ID", { day: 'numeric', month: 'short' })}
                    </p>
                </div>
            </div>
            <p className={`text-sm font-black ${color}`}>
                {tx.type === 'INCOME' ? '+' : '-'} {tx.amount.toLocaleString("id-ID")}
            </p>
        </div>
    );
}